# Note: 's' = seqStart (seconds), 'e' = seqEnd (seconds), 'i' = index, 'ip' = inPoint

# ---------------------------------------------------------------------------
# 2. SRT parsing
# ---------------------------------------------------------------------------
SRT_PATH = "/home/roylevi/projects/artoyina/editing/ep02/RoughCut.srt"

def srt_time_to_sec(t):
    """Convert SRT timestamp (HH:MM:SS,mmm) to seconds."""
    h, m, rest = t.split(":")
    s, ms = rest.split(",")
    return int(h) * 3600 + int(m) * 60 + int(s) + int(ms) / 1000.0

def parse_srt(path):
    with open(path, "r", encoding="utf-8-sig") as f:
        content = f.read()
    entries = []
    # Split on blank lines
    blocks = re.split(r"\n\s*\n", content.strip())
    for block in blocks:
        lines = block.strip().splitlines()
        if len(lines) < 2:
            continue
        # Find the timestamp line
        ts_line = None
        text_start = None
        for idx, line in enumerate(lines):
            if "-->" in line:
                ts_line = line
                text_start = idx + 1
                break
        if ts_line is None:
            continue
        parts = ts_line.split("-->")
        if len(parts) != 2:
            continue
        try:
            start = srt_time_to_sec(parts[0].strip())
            end = srt_time_to_sec(parts[1].strip())
        except Exception:
            continue
        text = " ".join(lines[text_start:]).strip()
        entries.append({"start": start, "end": end, "text": text})
    return entries

# ---------------------------------------------------------------------------
# 3. Intensity scoring
# ---------------------------------------------------------------------------
DRAMATIC_KEYWORDS = [
    "death", "dead", "bodies", "severed", "massacre", "slaughter", "horror",
    "horrifying", "obsessed", "chaos", "disaster", "war", "fire", "rage",
    "desperate", "terrifying", "overwhelm", "screaming", "dying", "rotting",
    "raft", "drowning", "stabbed", "violent", "blood", "kill", "burned",
    "murder", "collapse", "execution", "mad"
]
NAME_DROPS = [
    "gericault", "géricault", "delacroix", "napoleon", "napoléon", "ingres",
    "david", "caravaggio", "turner", "friedrich", "baudelaire", "courbet",
    "talleyrand"
]
YEAR_MENTIONS = ["1816", "1818", "1819", "1824", "1830", "1832", "1834", "1863"]

def score_entry(entry):
    text_lower = entry["text"].lower()
    score = 0.0
    for kw in DRAMATIC_KEYWORDS:
        if kw in text_lower:
            score += 0.4
    for name in NAME_DROPS:
        if name in text_lower:
            score += 0.2
    for year in YEAR_MENTIONS:
        if year in text_lower:
            score += 0.1
    # Duration-weighted: longer entries get proportionally more weight
    duration = max(entry["end"] - entry["start"], 0.001)
    weight = min(duration / 3.0, 2.0)  # normalize: 3s is baseline, cap at 2x
    score = score * weight
    return min(score, 1.0)

# ---------------------------------------------------------------------------
# 4. Generate clip plans
# ---------------------------------------------------------------------------
def gen_clip_plans(clips, srt_entries):
    clip_plans = {}
    for clip in clips:
        ci = clip["i"]
        if ci < 2:
            continue
        seq_start = clip["s"]
        seq_end = clip["e"]
        # Find overlapping SRT entries
        overlapping = [
            e for e in srt_entries
            if e["start"] < seq_end and e["end"] > seq_start
        ]
        # Build keyframes dict: offsetSec -> max scale
        kf_map = {}
        # Opening KF at offset 0
        kf_map[0.0] = 100
        for entry in overlapping:
            offset = max(0.0, entry["start"] - seq_start)
            offset = round(offset, 4)
            sc = score_entry(entry)
            scale = int(round(100 + sc * 45))
            scale = max(100, min(145, scale))
            if offset in kf_map:
                kf_map[offset] = max(kf_map[offset], scale)
            else:
                kf_map[offset] = scale
        # Sort by offset and build list
        kf_list = sorted(
            [{"offsetSec": k, "scale": v} for k, v in kf_map.items()],
            key=lambda x: x["offsetSec"]
        )
        clip_plans[ci] = kf_list
    return clip_plans

